import{c as o,Q as s,j as i,m as t}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Auth Bounce: Clearing Stale Zitadel Sessions Before Login","description":"","frontmatter":{},"headers":[],"relativePath":"auth-bounce.md","filePath":"auth-bounce.md","lastUpdated":1778829398000}'),a={name:"auth-bounce.md"};function n(l,e,r,c,d,h){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="auth-bounce-clearing-stale-zitadel-sessions-before-login" tabindex="-1">Auth Bounce: Clearing Stale Zitadel Sessions Before Login <a class="header-anchor" href="#auth-bounce-clearing-stale-zitadel-sessions-before-login" aria-label="Permalink to &quot;Auth Bounce: Clearing Stale Zitadel Sessions Before Login&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>When Console redirects to Zitadel&#39;s authorize endpoint with <code>login_hint</code>, Zitadel shows an account picker if a stale browser session exists for a different user — making Console&#39;s email collection step feel redundant.</p><p>OIDC <code>prompt</code> values don&#39;t solve this cleanly:</p><ul><li>No <code>prompt</code> + <code>login_hint</code> → account picker when a different session exists</li><li><code>prompt=login</code> → forces re-auth but Zitadel shows a &quot;You are signed in&quot; confirmation page that doesn&#39;t auto-redirect</li><li><code>prompt=select_account</code> → always shows the account picker</li></ul><h2 id="solution" tabindex="-1">Solution <a class="header-anchor" href="#solution" aria-label="Permalink to &quot;Solution&quot;">​</a></h2><p>A <strong>two-step redirect</strong> via a dedicated <code>/auth-bounce</code> route that clears all Zitadel sessions before initiating the authorize flow.</p><h3 id="flow" tabindex="-1">Flow <a class="header-anchor" href="#flow" aria-label="Permalink to &quot;Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User enters email on Console login page</span></span>
<span class="line"><span>  → Console resolves org/IdP via /api/v1/login/resolve-org</span></span>
<span class="line"><span>  → Stores routing context (no secrets) in sessionStorage</span></span>
<span class="line"><span>  → Redirects to Zitadel /oidc/v1/end_session?post_logout_redirect_uri=.../auth-bounce</span></span>
<span class="line"><span>  → Zitadel clears all browser sessions, redirects to /auth-bounce</span></span>
<span class="line"><span>  → AuthBouncePage reads context from sessionStorage, removes it</span></span>
<span class="line"><span>  → Calls redirectConsoleLogin() or redirectExternalToZitadel() with fresh PKCE</span></span>
<span class="line"><span>  → Zitadel shows clean login form with login_hint pre-filled — no account picker</span></span></code></pre></div><p>This works for both Console&#39;s own login flow and the external app gateway flow.</p><h3 id="what-gets-stored-in-sessionstorage" tabindex="-1">What gets stored in sessionStorage <a class="header-anchor" href="#what-gets-stored-in-sessionstorage" aria-label="Permalink to &quot;What gets stored in sessionStorage&quot;">​</a></h3><p>Key: <code>pending_login_context</code></p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Console flow</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;console&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">loginOpts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { orgId</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, loginHint</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, idpId</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// External flow</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ flow: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;external&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, loginOpts: { orgId?, loginHint?, idpId? }, externalParams: ExternalOIDCParams }</span></span></code></pre></div><p><strong>Security</strong>: No PKCE verifier, no tokens, no authorize URLs are stored — only the routing context that was already visible in the URL query params or form input. PKCE is regenerated fresh on <code>/auth-bounce</code>.</p><h3 id="files-to-modify" tabindex="-1">Files to modify <a class="header-anchor" href="#files-to-modify" aria-label="Permalink to &quot;Files to modify&quot;">​</a></h3><h4 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h4><ol><li><p><strong><code>web/src/auth/login.ts</code></strong> — <code>redirectConsoleLogin</code> and <code>redirectExternalToZitadel</code></p><ul><li>Store routing context: <code>sessionStorage.setItem(&#39;pending_login_context&#39;, JSON.stringify(...))</code></li><li>Redirect to Zitadel&#39;s end_session: <code>{issuer}/oidc/v1/end_session?post_logout_redirect_uri={consoleOrigin}/auth-bounce</code></li></ul></li><li><p><strong><code>web/src/pages/AuthBouncePage.tsx</code></strong> — New page (minimal, single-purpose)</p><ul><li>Reads <code>pending_login_context</code> from sessionStorage and removes it</li><li>If <code>flow === &#39;console&#39;</code>: calls <code>redirectConsoleLogin(loginOpts)</code> (generates fresh PKCE)</li><li>If <code>flow === &#39;external&#39;</code>: calls <code>redirectExternalToZitadel(externalParams, loginOpts)</code></li><li>If no context found: redirects to <code>/</code> as fallback</li></ul></li><li><p><strong><code>web/src/routes/index.tsx</code></strong> — Register <code>/auth-bounce</code> route</p></li></ol><h4 id="backend-infrastructure" tabindex="-1">Backend / Infrastructure <a class="header-anchor" href="#backend-infrastructure" aria-label="Permalink to &quot;Backend / Infrastructure&quot;">​</a></h4><ol start="4"><li><p><strong><code>scripts/bootstrap/main.go</code></strong> — Register <code>/auth-bounce</code> as a post-logout redirect URI</p><ul><li>Change <code>postLogoutRedirectUris</code> from <code>[consoleRoot]</code> to <code>[consoleRoot, consoleRoot + &quot;/auth-bounce&quot;]</code></li></ul></li><li><p><strong><code>internal/zitadel/client.go</code></strong> — Same change in <code>CreateConsoleOIDCApp</code></p><ul><li>Change <code>postLogoutRedirectUris</code> from <code>[base]</code> to <code>[base, urlutil.Join(base, &quot;/auth-bounce&quot;)]</code></li></ul></li><li><p><strong>Existing Zitadel instances</strong> — Add <code>{consoleOrigin}/auth-bounce</code> to the Console Portal OIDC app&#39;s post-logout redirect URIs (or re-run bootstrap for dev)</p></li></ol><h3 id="why-auth-bounce-instead-of-redirecting-back-to" tabindex="-1">Why <code>/auth-bounce</code> instead of redirecting back to <code>/</code> <a class="header-anchor" href="#why-auth-bounce-instead-of-redirecting-back-to" aria-label="Permalink to &quot;Why \`/auth-bounce\` instead of redirecting back to \`/\`&quot;">​</a></h3><ul><li><strong>Single responsibility</strong>: <code>/auth-bounce</code> only handles the session-clearing resume — no route guards, no auth checks, no login page re-rendering</li><li><strong>Debuggability</strong>: Easy to see in browser network tab and logs when the bounce happens</li><li><strong>No interference</strong>: Normal logout continues to redirect to <code>/</code> as before; the <code>/auth-bounce</code> URI is only used by the session-clearing login flow</li></ul><h3 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h3><ol><li>Log in as one user (e.g., zitadel-admin)</li><li>Log out from Console</li><li>Go to <code>/</code> login page, enter a different email</li><li>Should NOT see Zitadel account picker — should go straight to password/IdP login</li><li>Test external flow: visit <code>/</code> with external OIDC params, enter email, verify no account picker</li><li>Visit <code>/auth-bounce</code> directly with no context — should redirect to <code>/</code></li></ol>`,23)])])}const g=o(a,[["render",n]]);export{u as __pageData,g as default};
